#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[105];
        scanf("%s", S);
        int chef = 0, opp = 0;
        for (int i = 0; S[i] != '\0'; ++i) {
            if (S[i] == '1') ++chef; else ++opp;
        }
        if (chef > opp) printf("WIN\n");
        else printf("LOSE\n");
    }
    return 0;
}

